mapper.select:
SELECT *
FROM annotation
WHERE task_id = #{taskId}
  AND document_id = #{documentId}
  AND user_id = #{userId}
LIMIT 1

mapper.update:
UPDATE annotation
SET status = #{status},
    is_final = #{isFinal},
    submitted_at = #{submittedAt}
WHERE id = #{id}

mapper.select:
SELECT COUNT(DISTINCT user_id)
FROM annotation
WHERE task_id = #{taskId}
  AND document_id = #{documentId}
  AND status = 'SUBMITTED'
